// frontend/src/components/jobs/JobDetails.js
import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './JobDetails.css';

const JobDetails = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const { user, isAuthenticated } = useAuth();
    const alert = useAlert();

    const [job, setJob] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [applying, setApplying] = useState(false);
    const [acceptingId, setAcceptingId] = useState(null);
    const [applicationData, setApplicationData] = useState({
        proposed_rate: '',
        message: ''
    });
    const [clientCredits, setClientCredits] = useState(null);
    const [showCreditModal, setShowCreditModal] = useState(false);
    const [selectedWorker, setSelectedWorker] = useState(null);
    const [hireSuccess, setHireSuccess] = useState(false);
    const [hiredWorker, setHiredWorker] = useState(null);

    useEffect(() => {
        loadJobDetails();
        if (user?.user_type === 'client') {
            checkClientCredits();
        }
    }, [id, user]);

    const loadJobDetails = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/jobs/${id}`);
            if (response.data.success) {
                setJob(response.data.data);
            } else {
                setError('Job not found');
            }
        } catch (error) {
            console.error('Error loading job:', error);
            setError('Failed to load job details');
        } finally {
            setLoading(false);
        }
    };

    const checkClientCredits = async () => {
        try {
            console.log('Checking client credits...');
            const response = await api.get('/client/hire-credits');
            console.log('Credits response:', response.data);

            if (response.data.success) {
                setClientCredits(response.data.data);
            } else {
                console.error('Failed to fetch credits:', response.data.message);
            }
        } catch (error) {
            console.error('Error checking credits:', error);
        }
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setApplicationData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    const handleApply = async (e) => {
        e.preventDefault();
        if (!isAuthenticated) {
            alert.warning('Please login to apply for jobs');
            navigate('/login', { state: { from: `/jobs/${id}` } });
            return;
        }

        if (user?.user_type !== 'worker') {
            alert.error('Only workers can apply for jobs');
            return;
        }

        if (!applicationData.proposed_rate) {
            alert.warning('Please enter your proposed rate');
            return;
        }

        setApplying(true);

        try {
            const response = await api.post(`/jobs/${id}/apply`, {
                proposed_rate: parseInt(applicationData.proposed_rate),
                message: applicationData.message
            });

            if (response.data.success) {
                alert.success('✅ Application submitted successfully!');
                setApplicationData({ proposed_rate: '', message: '' });
                loadJobDetails();
            } else {
                alert.error(response.data.message || 'Failed to apply');
            }
        } catch (error) {
            console.error('Apply error:', error);
            if (error.response?.status === 400 && error.response?.data?.message === 'You need an active application pass to apply for jobs') {
                alert.confirm(
                    'You need an application pass to apply for jobs. Would you like to buy one now?',
                    () => navigate('/worker/pass'),
                    () => {},
                    'Application Pass Required',
                    'Buy Pass',
                    'Cancel'
                );
            } else {
                alert.error(error.response?.data?.message || 'Failed to apply. Please try again.');
            }
        } finally {
            setApplying(false);
        }
    };

    const handleViewWorkerProfile = (workerId) => {
        navigate(`/workers/${workerId}`, { 
            state: { 
                fromClient: true,
                jobId: job?.id,
                canHire: true 
            } 
        });
    };

    const handleHireClick = (application) => {
        console.log('Hire clicked for application:', application);
        console.log('Current client credits:', clientCredits);

        setSelectedWorker(application);

        // Check if client has credits
        if (!clientCredits) {
            console.log('No client credits data');
            alert.error('Unable to verify your credits. Please refresh and try again.');
            return;
        }

        // Check if client has any active packages
        if (clientCredits.active_packages === 0) {
            console.log('No active packages');
            setShowCreditModal(true);
            return;
        }

        // Check if client has remaining credits
        if (clientCredits.total_remaining === 0) {
            console.log('Zero credits remaining');
            setShowCreditModal(true);
            return;
        }

        // If unlimited or has credits, proceed with confirmation
        console.log('Credits available, showing confirmation');
        alert.confirm(
            `You are about to hire ${application.worker_name} for R${application.proposed_rate}. This will use 1 hire credit.`,
            () => processHire(application),
            () => {},
            'Confirm Hire',
            'Yes, Hire',
            'Cancel'
        );
    };

    const processHire = async (application) => {
        setAcceptingId(application.id);

        try {
            const response = await api.post(`/jobs/${job.id}/hire`, {
                worker_id: application.worker_id,
                agreed_rate: application.proposed_rate
            });

            if (response.data.success) {
                setHireSuccess(true);
                setHiredWorker({
                    name: application.worker_name,
                    phone: response.data.data.worker_phone,
                    email: response.data.data.worker_email
                });

                // Show success message with contact details
                alert.success(
                    `✅ Successfully hired ${application.worker_name}! Contact them at ${response.data.data.worker_phone}`
                );

                // Refresh job details to show updated status
                loadJobDetails();
                checkClientCredits();
            }
        } catch (error) {
            console.error('Hire error:', error);
            if (error.response?.status === 400) {
                if (error.response?.data?.message?.includes('Insufficient credits')) {
                    setShowCreditModal(true);
                } else {
                    alert.error(error.response?.data?.message || 'Failed to hire worker');
                }
            } else {
                alert.error('Failed to hire worker. Please try again.');
            }
        } finally {
            setAcceptingId(null);
            setSelectedWorker(null);
        }
    };

    const handleBuyCredits = () => {
        setShowCreditModal(false);
        navigate('/client/packages');
    };

    const formatDate = (dateString) => {
        if (!dateString) return 'Not specified';
        const date = new Date(dateString);
        return date.toLocaleDateString('en-ZA', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
        });
    };

    const getUrgencyColor = (urgency) => {
        switch (urgency) {
            case 'urgent': return { bg: '#FEE2E2', color: '#DC2626', text: '🚨 Urgent' };
            case 'high': return { bg: '#FEF3C7', color: '#D97706', text: '⚡ High' };
            case 'medium': return { bg: '#DBEAFE', color: '#2563EB', text: '📋 Medium' };
            default: return { bg: '#E5E7EB', color: '#4B5563', text: '🟢 Low' };
        }
    };

    const getInitials = (name) => {
        if (!name) return 'W';
        return name.split(' ').map(n => n[0]).join('').toUpperCase().substring(0, 2);
    };

    const handleBack = () => {
        navigate(-1);
    };

    if (loading) {
        return (
            <div className="loading-container">
                <div className="loading-spinner">Loading job details...</div>
            </div>
        );
    }

    if (error || !job) {
        return (
            <div className="error-container">
                <h2>❌ Error</h2>
                <p>{error || 'Job not found'}</p>
                <button onClick={handleBack} className="btn-primary">Go Back</button>
            </div>
        );
    }

    const urgency = getUrgencyColor(job.urgency);
    const hasApplied = job.applications?.some(app => app.worker_id === user?.id);
    const isOwner = job.client_id === user?.id;
    const isWorker = user?.user_type === 'worker';
    const isJobHired = job.status === 'hired' || job.status === 'in_progress' || job.status === 'completed';

    return (
        <div className="job-details-container">
            <div className="job-details">
                {/* Back Button */}
                <div className="back-navigation">
                    <button onClick={handleBack} className="back-button">
                        ← Back to Jobs
                    </button>
                </div>

                {/* Job Status Banner - Show if job is already hired */}
                {isJobHired && (
                    <div className="job-status-banner">
                        <span className="banner-icon">✅</span>
                        <div className="banner-text">
                            <h3>This job has been assigned</h3>
                            <p>A worker has been hired for this position</p>
                        </div>
                    </div>
                )}

                {/* Job Header */}
                <div className="job-header">
                    <h1>{job.title}</h1>

                    <div className="job-meta-grid">
                        <div className="meta-item">
                            <span className="meta-icon">📍</span>
                            <span>{job.township || 'Location not specified'}</span>
                        </div>

                        <div className="meta-item">
                            <span className="meta-icon">📅</span>
                            <span>Posted {formatDate(job.created_at)}</span>
                        </div>

                        <div className="meta-item">
                            <span className="meta-icon">📋</span>
                            <span>Job ID: {job.job_code || 'N/A'}</span>
                        </div>

                        <div className="urgency-badge" style={{ backgroundColor: urgency.bg, color: urgency.color }}>
                            {urgency.text}
                        </div>
                    </div>
                </div>

                {/* Budget Card */}
                <div className="budget-card">
                    <div className="budget-info">
                        <span className="budget-label">Budget Range</span>
                        <span className="budget-amount">
                            R {job.budget_min?.toLocaleString()} - R {job.budget_max?.toLocaleString()}
                        </span>
                    </div>
                    {job.estimated_hours && (
                        <div className="estimated-time">
                            ⏱️ Estimated {job.estimated_hours} hours
                        </div>
                    )}
                </div>

                {/* Description Section */}
                <div className="description-section">
                    <h2>Description</h2>
                    <p>{job.description || 'No description provided'}</p>
                </div>

                {/* Details Grid */}
                <div className="details-grid">
                    {job.category && (
                        <div className="detail-card">
                            <span className="detail-label">Category</span>
                            <span className="detail-value">{job.category}</span>
                        </div>
                    )}

                    {job.subcategory && (
                        <div className="detail-card">
                            <span className="detail-label">Subcategory</span>
                            <span className="detail-value">{job.subcategory}</span>
                        </div>
                    )}

                    {job.preferred_date && (
                        <div className="detail-card">
                            <span className="detail-label">Preferred Date</span>
                            <span className="detail-value">{formatDate(job.preferred_date)}</span>
                        </div>
                    )}

                    {job.preferred_time && (
                        <div className="detail-card">
                            <span className="detail-label">Preferred Time</span>
                            <span className="detail-value">{job.preferred_time}</span>
                        </div>
                    )}
                </div>

                {/* Materials Section */}
                {job.materials_provided && (
                    <div className="materials-section">
                        <h2>Materials Provided</h2>
                        <p className="materials-note">✓ Client will provide materials</p>
                        {job.materials_description && (
                            <p className="materials-description">{job.materials_description}</p>
                        )}
                    </div>
                )}

                {/* Safety Requirements */}
                {job.safety_requirements && (
                    <div className="safety-section">
                        <h2>Safety Requirements</h2>
                        <p>{job.safety_requirements}</p>
                    </div>
                )}

                {/* Credit Status for Client */}
                {isOwner && clientCredits && (
                    <div className="credit-status">
                        <div className="credit-info">
                            <span className="credit-icon">💳</span>
                            <div>
                                <h3>Your Hire Credits</h3>
                                <p className="credit-amount">
                                    {clientCredits.total_remaining === 'Unlimited' ? '♾️ Unlimited' : `${clientCredits.total_remaining} credits remaining`}
                                </p>
                            </div>
                        </div>
                        <Link to="/client/my-packages" className="btn-view-packages">
                            View Packages
                        </Link>
                    </div>
                )}

                {/* ========== APPLICATIONS SECTION - VISIBLE TO JOB OWNER ========== */}
                {isOwner && (
                    <div className="applications-section">
                        <div className="applications-header">
                            <h2>📋 Applications ({job.applications?.length || 0})</h2>
                            {job.applications?.length > 0 && (
                                <span className="applications-note">
                                    {job.applications.filter(a => a.status === 'pending').length} pending
                                </span>
                            )}
                        </div>

                        {!job.applications || job.applications.length === 0 ? (
                            <div className="no-applications">
                                <div className="no-apps-icon">📭</div>
                                <h3>No applications yet</h3>
                                <p>When workers apply for this job, they'll appear here</p>
                            </div>
                        ) : (
                            <div className="applications-list">
                                {job.applications.map((app) => {
                                    const isHired = app.status === 'accepted';
                                    return (
                                        <div key={app.id} className={`application-item ${isHired ? 'hired' : ''}`}>
                                            <div className="application-item-header">
                                                <div className="applicant-info">
                                                    <button 
                                                        onClick={() => handleViewWorkerProfile(app.worker_id)}
                                                        className="applicant-avatar"
                                                        disabled={isJobHired && !isHired}
                                                    >
                                                        {getInitials(app.worker_name)}
                                                    </button>
                                                    <div>
                                                        <button 
                                                            onClick={() => handleViewWorkerProfile(app.worker_id)}
                                                            className="applicant-name-link"
                                                            disabled={isJobHired && !isHired}
                                                        >
                                                            {app.worker_name}
                                                        </button>
                                                        <div className="applicant-rating">
                                                            {'⭐'.repeat(Math.round(app.worker_rating || 0))}
                                                            <span>({app.worker_rating?.toFixed(1) || '0.0'})</span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <div className="application-status-badge">
                                                    <span className={`status-dot ${isHired ? 'accepted' : app.status}`}></span>
                                                    {isHired ? 'Hired' : app.status}
                                                </div>
                                            </div>

                                            <div className="application-item-body">
                                                <div className="proposed-rate">
                                                    <span className="rate-label">Proposed Rate:</span>
                                                    <span className="rate-value">R {app.proposed_rate}</span>
                                                </div>

                                                {app.message && (
                                                    <div className="applicant-message">
                                                        <strong>Message:</strong>
                                                        <p>{app.message}</p>
                                                    </div>
                                                )}

                                                <div className="application-meta">
                                                    <span>📅 Applied {formatDate(app.created_at)}</span>
                                                    {app.worker_skill && (
                                                        <span className="skill-tag">{app.worker_skill}</span>
                                                    )}
                                                </div>

                                                {isHired && (
                                                    <div className="hired-badge">
                                                        <span>✅ HIRED FOR THIS JOB</span>
                                                    </div>
                                                )}
                                            </div>

                                            <div className="application-item-footer">
                                                <button 
                                                    onClick={() => handleViewWorkerProfile(app.worker_id)}
                                                    className="btn-view-profile"
                                                    disabled={isJobHired && !isHired}
                                                >
                                                    View Profile
                                                </button>

                                                {app.status === 'pending' && !isJobHired && (
                                                    <button 
                                                        onClick={() => handleHireClick(app)}
                                                        className="btn-hire-worker"
                                                        disabled={acceptingId === app.id}
                                                    >
                                                        {acceptingId === app.id ? 'Processing...' : 'Hire Worker'}
                                                    </button>
                                                )}
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                )}

                {/* Hired Worker Contact Info - Show if job is hired */}
                {isOwner && job.hired_worker && (
                    <div className="hired-worker-section">
                        <h2>✅ Hired Worker</h2>
                        <div className="hired-worker-card">
                            <div className="hired-worker-info">
                                <div className="worker-avatar-large">
                                    {getInitials(job.hired_worker.name)}
                                </div>
                                <div>
                                    <h3>{job.hired_worker.name}</h3>
                                    <p className="worker-rating">⭐ {job.hired_worker.rating?.toFixed(1) || 'New'}</p>
                                </div>
                            </div>
                            <div className="contact-details">
                                <p><strong>📞 Phone:</strong> {job.hired_worker.phone}</p>
                                {job.hired_worker.email && <p><strong>✉️ Email:</strong> {job.hired_worker.email}</p>}
                            </div>
                            <Link to={`/workers/${job.hired_worker.id}`} className="btn-view-full-profile">
                                View Full Profile
                            </Link>
                        </div>
                    </div>
                )}

                {/* Apply Section (for workers) */}
                {isWorker && !isOwner && !hasApplied && !isJobHired && (
                    <div className="apply-section">
                        <h2>Apply for this job</h2>

                        <form onSubmit={handleApply} className="apply-form">
                            <div className="form-group">
                                <label>Your proposed rate (R)</label>
                                <input
                                    type="number"
                                    name="proposed_rate"
                                    value={applicationData.proposed_rate}
                                    onChange={handleInputChange}
                                    placeholder={`Between R${job.budget_min} - R${job.budget_max}`}
                                    min={job.budget_min}
                                    max={job.budget_max}
                                    required
                                />
                                <small>Suggested range: R{job.budget_min} - R{job.budget_max}</small>
                            </div>

                            <div className="form-group">
                                <label>Message to client (optional)</label>
                                <textarea
                                    name="message"
                                    value={applicationData.message}
                                    onChange={handleInputChange}
                                    placeholder="Tell the client why you're the best person for this job..."
                                    rows="4"
                                />
                            </div>

                            <button 
                                type="submit" 
                                className="btn-submit"
                                disabled={applying}
                            >
                                {applying ? 'Submitting...' : 'Apply for Job'}
                            </button>
                        </form>
                    </div>
                )}

                {/* Already Applied Message */}
                {isWorker && hasApplied && !isJobHired && (
                    <div className="applied-message">
                        <span className="applied-icon">✅</span>
                        <div>
                            <h3>You have already applied for this job</h3>
                            <p>Check your dashboard for application status</p>
                        </div>
                        <Link to="/dashboard" className="btn-view-applications">
                            View Dashboard
                        </Link>
                    </div>
                )}

                {/* Job Hired Message for Workers */}
                {isWorker && isJobHired && (
                    <div className="job-closed-message">
                        <span className="closed-icon">🔒</span>
                        <div>
                            <h3>This job has been assigned</h3>
                            <p>A worker has already been hired for this position</p>
                        </div>
                    </div>
                )}

                {/* Login Prompt */}
                {!isAuthenticated && (
                    <div className="login-prompt">
                        <p>Want to apply for this job?</p>
                        <Link to="/login" className="btn-primary">
                            Sign in to Apply
                        </Link>
                    </div>
                )}
            </div>

            {/* Insufficient Credits Modal */}
            {showCreditModal && (
                <div className="modal-overlay" onClick={() => setShowCreditModal(false)}>
                    <div className="credit-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header warning">
                            <h2>⚠️ Insufficient Credits</h2>
                            <button className="modal-close" onClick={() => setShowCreditModal(false)}>×</button>
                        </div>

                        <div className="modal-body">
                            <div className="credit-icon-large">💳</div>
                            <h3>You don't have enough hire credits</h3>
                            <p>You need at least 1 hire credit to hire a worker.</p>

                            {clientCredits && (
                                <div className="current-credits">
                                    <p>Your current credits: <strong>{clientCredits.total_remaining === 'Unlimited' ? '♾️ Unlimited' : clientCredits.total_remaining}</strong></p>
                                </div>
                            )}

                            <div className="modal-actions">
                                <button 
                                    className="btn-cancel"
                                    onClick={() => setShowCreditModal(false)}
                                >
                                    Cancel
                                </button>
                                <button 
                                    className="btn-buy-credits"
                                    onClick={handleBuyCredits}
                                >
                                    Buy Credits
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default JobDetails;
